69     inline Rectf AnchoredPosition(const std::optional<Rectf> &parentRect, const Rectf &dstRect, const Vector2f &screenAnchor, const Vector2f &spritePivot)
70     {
71         Rectf parent;
72         if (parentRect)
73         {
74             parent = parentRect.value();
75             parent.SetPosition(parent.GetPosition() + parent.GetSize() / 2.0f);
76         }
77         else
78         {
79             Vector2f logical{static_cast<float>(CONST_RENDER_LOGICAL_X), static_cast<float>(CONST_RENDER_LOGICAL_Y)};
80             parent = {logical / 2.0f, logical};
81         }
82         auto elementSize = dstRect.GetSize();
83         Vector2f pos = (parent.GetSize() * screenAnchor) / 2.0f + parent.GetPosition();
84         pos -= (elementSize / 2.0f) * spritePivot + (elementSize / 2.0f);
85         pos += dstRect.GetPosition();
86 
87         return {pos, dstRect.GetSize()};
88     }
89 }
